mapper.sql:
p.enabled = TRUE

    AND p.category_id = #{categoryId}


    AND p.equipment_role = #{equipmentRole}


    AND p.brand = #{brand}


    AND p.model = #{model}


    AND EXISTS (
        SELECT 1
        FROM product_use_cases puc
        JOIN catalog_use_cases uc ON uc.id = puc.use_case_id
        WHERE puc.product_id = p.id
          AND puc.use_case_id = #{useCaseId}
          AND uc.enabled = TRUE
    )


    AND EXISTS (
        SELECT 1
        FROM product_skus ps
        WHERE ps.product_id = p.id
          AND ps.enabled = TRUE
          AND ps.sale_price <= #{maxPrice}
    )


    AND (
        p.model = #{keyword}
        OR MATCH(p.name, p.brand, p.model, p.description)
           AGAINST(#{keyword} IN NATURAL LANGUAGE MODE)
    )

mapper.select:
SELECT p.id, p.category_id, p.equipment_role, p.name, p.brand, p.model, p.description FROM products p WHERE ORDER BY
CASE WHEN p.model = #{keyword} THEN 0 ELSE 1 END ASC, MATCH(p.name, p.brand, p.model, p.description) AGAINST(#{keyword} IN NATURAL LANGUAGE MODE) DESC,
p.id ASC LIMIT #{size} OFFSET #{offset}

SELECT puc.product_id, uc.id AS use_case_id, uc.code, uc.name, puc.weight FROM product_use_cases puc JOIN catalog_use_cases uc ON uc.id = puc.use_case_id WHERE uc.enabled = TRUE AND puc.product_id IN
#{productId}
ORDER BY puc.product_id ASC, puc.weight DESC, uc.id ASC
